     1→<?php
     2→/**
     3→ * Plugin Name:  BIT Elementor SVG Widget
     4→ * Description:  Widget Elementor "Bureau SVG" — carrega SVGs inline do tema
     5→ *               com preview no editor. Suporta qualquer subsite da rede.
     6→ *               Substitui [wpml_logo] e resolve bug de path do JetElements.
     7→ * Version:      1.4.1
     8→ * Author:       Bureau IT
     9→ * Network:      true
    10→ */
    11→
    12→if ( ! defined( 'ABSPATH' ) ) exit;
    13→
    14→add_action( 'elementor/widgets/register', function ( $widgets_manager ) {
    15→    if ( ! class_exists( '\Elementor\Widget_Base' ) ) return;
    16→
    17→    // Classe definida aqui (dentro do hook) para evitar fatal error:
    18→    // PHP resolve a herança em tempo de execução, não de compilação.
    19→    // Fora do hook, Elementor ainda não carregou → "Class not found".
    20→    class Bureau_SVG_Widget extends \Elementor\Widget_Base {
    21→
    22→    public function get_name()        { return 'bureau_svg'; }
    23→    public function get_title()       { return 'Bureau SVG'; }
    24→    public function get_icon()        { return 'eicon-image'; }
    25→    public function get_categories()  { return [ 'general' ]; }
    26→    public function get_keywords()    { return [ 'svg', 'bureau', 'logo', 'icon', 'inline' ]; }
    27→
    28→    private function get_svg_options() {
    29→        $svg_dir  = get_stylesheet_directory() . '/svg/';
    30→        $options  = [ '' => '— selecionar —' ];
    31→        $name_map = [
    32→            'logo-concertacao'        => 'Logo Concertação',
    33→            'espiral-concertacao'     => 'Ícone Espiral',
    34→            'espiral-do-conhecimento' => 'Espiral do Conhecimento',
    35→        ];
    36→        foreach ( glob( $svg_dir . '*.svg' ) ?: [] as $file ) {
    37→            $slug             = basename( $file, '.svg' );
    38→            $options[ $slug ] = $name_map[ $slug ] ?? $slug;
    39→        }
    40→        return $options;
    41→    }
    42→
    43→    protected function register_controls() {
    44→        $this->start_controls_section( 'content_section', [
    45→            'label' => 'SVG',
    46→            'tab'   => \Elementor\Controls_Manager::TAB_CONTENT,
    47→        ] );
    48→
    49→        $this->add_control( 'svg_name', [
    50→            'label'   => 'Arquivo SVG',
    51→            'type'    => \Elementor\Controls_Manager::SELECT,
    52→            'options' => $this->get_svg_options(),
    53→            'default' => '',
    54→        ] );
    55→
    56→        $this->add_responsive_control( 'svg_width', [
    57→            'label'      => 'Largura',
    58→            'type'       => \Elementor\Controls_Manager::SLIDER,
    59→            'size_units' => [ 'px', '%', 'vw' ],
    60→            'range'      => [
    61→                'px' => [ 'min' => 50,  'max' => 800, 'step' => 10 ],
    62→                '%'  => [ 'min' => 5,   'max' => 100, 'step' => 5  ],
    63→                'vw' => [ 'min' => 1,   'max' => 50,  'step' => 1  ],
    64→            ],
    65→            'default'    => [ 'unit' => 'px', 'size' => 200 ],
    66→            'selectors'  => [
    67→                '{{WRAPPER}} svg' => 'width: {{SIZE}}{{UNIT}}; height: auto;',
    68→            ],
    69→        ] );
    70→
    71→        $this->add_control( 'svg_class', [
    72→            'label'       => 'CSS Class',
    73→            'type'        => \Elementor\Controls_Manager::TEXT,
    74→            'placeholder' => 'minha-classe outra-classe',
    75→            'ai'          => [ 'active' => false ],
    76→        ] );
    77→
    78→        $this->add_control( 'svg_id', [
    79→            'label'       => 'CSS ID',
    80→            'type'        => \Elementor\Controls_Manager::TEXT,
    81→            'placeholder' => 'meu-id',
    82→            'ai'          => [ 'active' => false ],
    83→        ] );
    84→
    85→        $this->add_control( 'link_enabled', [
    86→            'label'        => 'Adicionar link',
    87→            'type'         => \Elementor\Controls_Manager::SWITCHER,
    88→            'label_on'     => 'Sim',
    89→            'label_off'    => 'Não',
    90→            'return_value' => 'yes',
    91→            'default'      => '',
    92→        ] );
    93→
    94→        $this->add_control( 'link_url', [
    95→            'label'       => 'URL do link',
    96→            'type'        => \Elementor\Controls_Manager::TEXT,
    97→            'placeholder' => 'Vazio = URL raiz da rede (auto)',
    98→            'description' => 'Vazio: usa network_home_url() com filtro wpml_home_url automaticamente '
    99→                           . '(retorna /en quando WPML estiver em inglês). '
   100→                           . 'ATENÇÃO: no site www-concertacao.com.br preencher manualmente com '
   101→                           . 'https://concertacaoamazonia.com.br (domínio diferente).',
   102→            'ai'          => [ 'active' => false ],
   103→            'condition'   => [ 'link_enabled' => 'yes' ],
   104→        ] );
   105→
   106→        $this->add_control( 'link_target', [
   107→            'label'     => 'Abrir link em',
   108→            'type'      => \Elementor\Controls_Manager::SELECT,
   109→            'options'   => [
   110→                '_self'  => 'Mesma aba',
   111→                '_blank' => 'Nova aba',
   112→            ],
   113→            'default'   => '_self',
   114→            'condition' => [ 'link_enabled' => 'yes' ],
   115→        ] );
   116→
   117→        $this->end_controls_section();
   118→
   119→        // ── Cor genérica (para SVGs com fill:currentColor) ──
   120→        $this->start_controls_section( 'style_section', [
   121→            'label' => 'Cor',
   122→            'tab'   => \Elementor\Controls_Manager::TAB_STYLE,
   123→        ] );
   124→
   125→        $this->add_control( 'svg_color', [
   126→            'label'     => 'Cor do SVG',
   127→            'type'      => \Elementor\Controls_Manager::COLOR,
   128→            'global'    => [
   129→                'default' => \Elementor\Core\Kits\Documents\Tabs\Global_Colors::COLOR_PRIMARY,
   130→            ],
   131→            'selectors' => [
   132→                '{{WRAPPER}}'     => 'color: {{VALUE}};',
   133→                '{{WRAPPER}} a'   => 'color: {{VALUE}};',
   134→                '{{WRAPPER}} svg' => 'color: {{VALUE}};',
   135→            ],
   136→            'description' => 'Funciona em SVGs que usam fill:currentColor (logo-concertacao, espiral-concertacao).',
   137→        ] );
   138→
   139→        $this->end_controls_section();
   140→
   141→        // ── Espiral do Conhecimento (somente quando selecionada) ──
   142→        $this->start_controls_section( 'spiral_section', [
   143→            'label'     => 'Espiral do Conhecimento',
   144→            'tab'       => \Elementor\Controls_Manager::TAB_STYLE,
   145→            'condition' => [ 'svg_name' => 'espiral-do-conhecimento' ],
   146→        ] );
   147→
   148→        $spiral_colors = [
   149→            'spiral_bg_color'       => [ 'Cor de fundo',              '--spiral2026-backgroundcolor' ],
   150→            'spiral_bg_hover_color' => [ 'Cor de fundo (hover)',       '--spiral2026-backgroundcolor-hover' ],
   151→            'spiral_line_color'     => [ 'Cor da linha principal',     '--spiral2026-mainline-color' ],
   152→            'spiral_center_color'   => [ 'Cor centro do gradiente',    '--spiral2026-middle-center-color' ],
   153→            'spiral_edge_color'     => [ 'Cor borda do gradiente',     '--spiral2026-middle-edge-color' ],
   154→            'spiral_flood_color'    => [ 'Cor flood (sombra)',         '--spiral2026-flood-color' ],
   155→            'spiral_rays_color'     => [ 'Cor dos 8 raios',            '--spiral2026-eightrays-color' ],
   156→            'spiral_text_color'     => [ 'Cor do texto',               '--spiral2026-foreignobject-color' ],
   157→        ];
   158→
   159→        foreach ( $spiral_colors as $control_id => [ $label, $css_var ] ) {
   160→            $this->add_control( $control_id, [
   161→                'label'     => $label,
   162→                'type'      => \Elementor\Controls_Manager::COLOR,
   163→                'global'    => [ 'active' => true ],
   164→                'selectors' => [
   165→                    '{{WRAPPER}} .SVGSpiral2026' => $css_var . ': {{VALUE}};',
   166→                ],
   167→            ] );
   168→        }
   169→
   170→        $this->add_control( 'spiral_fontsize', [
   171→            'label'      => 'Tamanho da fonte',
   172→            'type'       => \Elementor\Controls_Manager::SLIDER,
   173→            'size_units' => [ 'px' ],
   174→            'range'      => [ 'px' => [ 'min' => 8, 'max' => 32, 'step' => 1 ] ],
   175→            'selectors'  => [
   176→                '{{WRAPPER}} .SVGSpiral2026' => '--spiral2026-foreignobject-fontsize: {{SIZE}}{{UNIT}};',
   177→            ],
   178→        ] );
   179→
   180→        $this->end_controls_section();
   181→    }
   182→
   183→    /**
   184→     * Isola o <style> interno do SVG com um atributo data-scope único,
   185→     * evitando conflito de nomes de classes genéricas (ex: .cls-1) entre
   186→     * múltiplos SVGs inlined na mesma página.
   187→     *
   188→     * Escopo APENAS para SVGs que usam classes genéricas .cls-N.
   189→     * SVGs com classes únicas (ex: .SVGSpiral2026) são retornados sem modificação,
   190→     * preservando seus controles de estilo do Elementor e CSS interno complexo.
   191→     */
   192→    private function scope_svg_styles( string $svg, string $scope_id ): string {
   193→        // Só aplica scoping em SVGs com classes genéricas .cls-N
   194→        if ( ! preg_match( '/\.cls-[\w-]+\s*\{/', $svg ) ) {
   195→            return $svg;
   196→        }
   197→
   198→        // Injetar data-scope no elemento <svg>
   199→        $svg = preg_replace( '/<svg\b/', '<svg data-scope="' . esc_attr( $scope_id ) . '"', $svg, 1 );
   200→
   201→        // Scopar apenas os seletores .cls-* dentro dos blocos <style>
   202→        $svg = preg_replace_callback(
   203→            '/(<style[^>]*>)(.*?)(<\/style>)/is',
   204→            static function ( $m ) use ( $scope_id ) {
   205→                $scoped = preg_replace_callback(
   206→                    '/(\.cls-[\w-]+(?:\s*,\s*\.cls-[\w-]+)*)\s*\{/',
   207→                    static function ( $r ) use ( $scope_id ) {
   208→                        $selectors = array_map( 'trim', explode( ',', $r[1] ) );
   209→                        $prefixed  = array_map(
   210→                            static fn( $s ) => '[data-scope="' . $scope_id . '"] ' . $s,
   211→                            $selectors
   212→                        );
   213→                        return implode( ', ', $prefixed ) . ' {';
   214→                    },
   215→                    $m[2]
   216→                );
   217→                return $m[1] . $scoped . $m[3];
   218→            },
   219→            $svg
   220→        );
   221→
   222→        return $svg;
   223→    }
   224→
   225→    protected function render() {
   226→        $s = $this->get_settings_for_display();
   227→
   228→        $name = ! empty( $s['svg_name'] ) ? $s['svg_name'] : '';
   229→
   230→        if ( empty( $name ) ) return;
   231→
   232→        $file = get_stylesheet_directory() . '/svg/' . $name . '.svg';
   233→
   234→        if ( ! file_exists( $file ) ) return;
   235→
   236→        $svg = file_get_contents( $file );
   237→        if ( empty( $svg ) ) return;
   238→
   239→        // Remover declaração XML (inválida em HTML5 inline)
   240→        $svg = preg_replace( '/<\?xml[^?]*\?>\s*/i', '', $svg );
   241→
   242→        // Isolar CSS interno com data-scope para evitar conflitos entre SVGs inlined
   243→        $svg = $this->scope_svg_styles( $svg, 'bsvg-' . $this->get_id() );
   244→
   245→        // Injetar class no <svg>
   246→        if ( ! empty( $s['svg_class'] ) ) {
   247→            $class = esc_attr( $s['svg_class'] );
   248→            if ( preg_match( '/\bclass="[^"]*"/', $svg ) ) {
   249→                $svg = preg_replace( '/\bclass="([^"]*)"/', 'class="$1 ' . $class . '"', $svg, 1 );
   250→            } else {
   251→                $svg = preg_replace( '/<svg\b/', '<svg class="' . $class . '"', $svg, 1 );
   252→            }
   253→        }
   254→
   255→        // Injetar id no <svg>
   256→        if ( ! empty( $s['svg_id'] ) ) {
   257→            $id = esc_attr( $s['svg_id'] );
   258→            if ( preg_match( '/\bid="[^"]*"/', $svg ) ) {
   259→                $svg = preg_replace( '/\bid="[^"]*"/', 'id="' . $id . '"', $svg, 1 );
   260→            } else {
   261→                $svg = preg_replace( '/<svg\b/', '<svg id="' . $id . '"', $svg, 1 );
   262→            }
   263→        }
   264→
   265→        // Envolver em <a> se link_enabled = 'yes'
   266→        if ( ! empty( $s['link_enabled'] ) && $s['link_enabled'] === 'yes' ) {
   267→            $href   = ! empty( $s['link_url'] )
   268→                ? esc_url( $s['link_url'] )
   269→                : esc_url( apply_filters( 'wpml_home_url', network_home_url( '/' ) ) );
   270→            $target = ( $s['link_target'] ?? '_self' ) === '_blank'
   271→                ? ' target="_blank" rel="noopener noreferrer"'
   272→                : '';
   273→            $svg    = '<a href="' . $href . '"' . $target . '>' . $svg . '</a>';
   274→        }
   275→
   276→        echo $svg; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
