     9→
    10→// If this file is called directly, abort.
    11→if ( ! defined( 'WPINC' ) ) {
    12→	die;
    13→}
    14→
    15→if ( ! class_exists( 'Jet_Elements_Download_Handler' ) ) {
    16→
    17→	/**
    18→	 * Define Jet_Elements_Download_Handler class
    19→	 */
    20→	class Jet_Elements_Download_Handler {
    21→
    22→		/**
    23→		 * A reference to an instance of this class.
    24→		 *
    25→		 * @since 1.0.0
    26→		 * @var   object
    27→		 */
    28→		private static $instance = null;
    29→
    30→		/**
    31→		 * Download hook
    32→		 *
    33→		 * @var string
    34→		 */
    35→		private $hook = 'jet_download';
    36→
    37→		/**
    38→		 * Return nonce key for hashing URL
    39→		 * 
    40→		 * @return [type] [description]
    41→		 */
    42→		public function get_nonce_key() {
    43→
    44→			if ( defined( 'NONCE_SALT' ) ) {
    45→				return NONCE_SALT;
    46→			}
    47→
    48→			$encrypt_key = get_option( 'jet_elements_download_button_encrypt_key_start' );
    49→
    50→			if ( ! $encrypt_key ) {
    51→				$encrypt_key = $this->generate_security_key();
    52→				add_option( 'jet_elements_download_button_encrypt_key_start', $encrypt_key );
    53→			}
    54→
    55→			return $encrypt_key;
    56→
    57→		}
    58→
    59→		/**
    60→		 * Constructor for the class
    61→		 */
    62→		public function init() {
    63→			add_action( 'init', array( $this, 'process_download' ), 99 );
    64→			add_action( 'init', array( $this, 'reset_download_hashes' ), 99 );
    65→		}
    66→
    67→		public function get_reset_hashes_url() {
    68→			return add_query_arg(
    69→				array( $this->hook() . '_reset' => 1, 'nonce' => wp_create_nonce( $this->hook() ) ),
    70→				esc_url( home_url( '/' ) )
    71→			);
    72→		}
    73→
    74→		public function reset_download_hashes() {
    75→
    76→			if ( empty( $_GET[ $this->hook() . '_reset' ] ) ) {
    77→				return;
    78→			}
    79→
    80→			$nonce = ! empty( $_GET['nonce'] ) ? sanitize_text_field( wp_unslash( $_GET['nonce'] ) ) : false;
    81→
    82→			if ( ! $nonce || ! wp_verify_nonce( $nonce, $this->hook() ) ) {
    83→				wp_die( 
    84→					esc_html__( 'Your link is expired, please return to the previous page, reload it and try again.', 'jet-elements' ),
    85→					esc_html__( 'Error', 'jet-elements' )
    86→				);
    87→			}
    88→
    89→			if ( ! current_user_can( 'manage_options' ) ) {
    90→				wp_die( 
    91→					esc_html__( 'Only site admins allowed to do this.', 'jet-elements' ),
    92→					esc_html__( 'Error', 'jet-elements' )
    93→				);
    94→			}
    95→
    96→			delete_option( 'jet_elements_download_button_hashes' );
    97→
    98→			wp_die( 
    99→				esc_html__( 'Download hashes successfully reseted. If you are using any caching plugins, you also need to reset cache to ensure all valid hashes regenerated.', 'jet-elements' ),
   100→				esc_html__( 'Success!', 'jet-elements' )
   101→			);
   102→
   103→		}
   104→
   105→		/**
   106→		 * Generate security key
   107→		 *
   108→		 * @var string
   109→		 */
   110→		private function generate_security_key() {
   111→			return absint( (int)( ( time() / random_int( 11, 100 ) ) * random_int( 2, 1000 ) ) );
   112→		}
   113→
   114→		/**
   115→		 * Returns download hook name
   116→		 *
   117→		 * @return string
   118→		 */
   119→		public function hook() {
   120→			return $this->hook;
   121→		}
   122→
   123→		/**
   124→		 * Get plain encrypted ID
   125→		 * 
   126→		 * @param  [type] $id [description]
   127→		 * @return [type]     [description]
   128→		 */
   129→		public function get_encrypted_id( $id ) {
   130→			return sha1( $this->get_nonce_key() . $id );
   131→		}
   132→
   133→		/**
   134→		 * Encrypt download ID
   135→		 *
   136→		 * @return string
   137→		 */
   138→		private function encrypt_id( $id ) {
   139→
   140→			$hash = $this->get_encrypted_id( $id );
   141→			$hash_map = get_option( 'jet_elements_download_button_hashes', [] );
   142→			$sanitize_hashes = false;
   143→			$hash_map[ $hash ] = $id;
   144→
   145→			update_option( 'jet_elements_download_button_hashes', $hash_map, false );
   146→
   147→			return $hash;
   148→		}
   149→
   150→		/**
   151→		 * Decrypt download ID
   152→		 *
   153→		 * @return string
   154→		 */
   155→		private function decrypt_id( $id ) {
   156→			$hash_map = get_option( 'jet_elements_download_button_hashes', [] );
   157→			return isset( $hash_map[ $id ] ) ? $hash_map[ $id ] : false;
   158→		}
   159→
   160→		/**
   161→		 * Get download link for passed ID.
   162→		 *
   163→		 * @param  integer $id Media post ID.
   164→		 * @return string
   165→		 */
   166→		public function get_download_link( $id = 0, $is_encrypted = '' ) {
   167→			
   168→			// For security reasons now is encrypted in any case
   169→			$id = $this->encrypt_id( $id );
   170→
   171→			return add_query_arg(
   172→				array( $this->hook() => $id ),
   173→				esc_url( home_url( '/' ) )
   174→			);
   175→		}
   176→
   177→		/**
   178→		 * Get file size by attachment ID
   179→		 * @param  integer $id [description]
   180→		 * @return [type]      [description]
   181→		 */
   182→		public function get_file_size( $id = 0 ) {
   183→
   184→			$file_path = get_attached_file( $id );
   185→
   186→			if ( ! $file_path ) {
   187→				return;
   188→			}
   189→
   190→			$file_size = filesize( $file_path );
   191→
   192→			return size_format( $file_size );
   193→		}
   194→
   195→		/**
   196→		 * Check if is download request and handle it.
   197→		 */
   198→		public function process_download() {
   199→
   200→			if ( empty( $_GET[ $this->hook() ] ) ) { // phpcs:ignore
   201→				return;
   202→			}
   203→
   204→			$encrypted_id = sanitize_text_field( wp_unslash( $_GET[ $this->hook() ] ) ); // phpcs:ignore
   205→			$id           = absint( $this->decrypt_id( $encrypted_id ) );
   206→
   207→			if ( ! $id ) {
   208→				return;
   209→			}
   210→
   211→			$post = get_post( $id );
   212→
   213→			if ( 'attachment' !== $post->post_type ) {
   214→				return;
   215→			}
   216→
   217→			$file_path = get_attached_file( $id );
   218→
   219→			if ( ! is_file( $file_path ) ) {
   220→				return;
   221→			}
   222→
   223→			// Clear all output buffers to prevent file corruption
   224→			while ( ob_get_level() ) {
   225→				@ob_end_clean();
   226→			}
   227→
   228→			if ( ini_get( 'zlib.output_compression' ) ) {
   229→				ini_set('zlib.output_compression', 'Off');
   230→			}
   231→
   232→			// get the file mime type using the file extension
   233→			switch( strtolower( substr( strrchr( $file_path, '.' ), 1 ) ) ) {
   234→				case 'pdf':
   235→					$mime = 'application/pdf';
   236→					break;
   237→				case 'zip':
   238→					$mime = 'application/zip';
   239→					break;
   240→				case 'jpeg':
   241→				case 'jpg':
   242→					$mime = 'image/jpg';
   243→					break;
   244→				default:
   245→					$mime = 'application/force-download';
   246→					break;
   247→			}
   248→
   249→			header( 'Pragma: public' );
   250→			header( 'Expires: 0' );
   251→			header( 'Cache-Control: must-revalidate, post-check=0, pre-check=0');
   252→			header( 'Last-Modified: ' . gmdate( 'D, d M Y H:i:s', @filemtime( $file_path ) ) . ' GMT' );
   253→			header( 'Cache-Control: private', false );
   254→			header( 'Content-Type: ' . $mime );
   255→			header( 'Content-Disposition: attachment; filename="' . basename( $file_path ) . '"' );
   256→			header( 'Content-Transfer-Encoding: binary' );
   257→			header( 'Content-Length: ' . @filesize( $file_path ) );
