   267→		 * Process chuncked download
   268→		 *
   269→		 * @param  string $file     Filepath
   270→		 * @param  bool   $retbytes
   271→		 * @return mixed
   272→		 */
   273→		public function readfile_chunked( $filename, $retbytes = true ) {
   274→
   275→			$chunksize = 1 * ( 1024 * 1024 );
   276→			$buffer    = '';
   277→			$cnt       = 0;
   278→			$handle    = fopen( $filename, 'rb' );
   279→
   280→			if ( false === $handle ) {
   281→				return false;
   282→			}
   283→
   284→			while ( ! feof( $handle ) ) {
   285→				$buffer = fread( $handle, $chunksize );
   286→				echo $buffer; // phpcs:ignore
   287→
   288→				if ( ob_get_level() > 0 ) {
   289→					ob_flush();
   290→				}
   291→				flush();
   292→				if ( $retbytes ) {
   293→					$cnt += strlen( $buffer );
   294→				}
   295→			}
   296→
   297→			$status = fclose($handle);
   298→
   299→			if ( $retbytes && $status ) {
   300→				return $cnt; // return num. bytes delivered like readfile() does.
   301→			}
   302→
   303→			return $status;
   304→		}
