   307→		 * Returns the instance.
   308→		 *
   309→		 * @since  1.0.0
   310→		 * @return object
   311→		 */
   312→		public static function get_instance() {
   313→
   314→			// If the single instance hasn't been set, set it now.
   315→			if ( null == self::$instance ) {
   316→				self::$instance = new self;
   317→			}
   318→			return self::$instance;
   319→		}
   320→	}
   321→
   322→}
