   183→    /**
   184→     * Isola o <style> interno do SVG com um atributo data-scope único,
   185→     * evitando conflito de nomes de classes genéricas (ex: .cls-1) entre
   186→     * múltiplos SVGs inlined na mesma página.
   187→     *
   188→     * Escopo APENAS para SVGs que usam classes genéricas .cls-N.
   189→     * SVGs com classes únicas (ex: .SVGSpiral2026) são retornados sem modificação,
   190→     * preservando seus controles de estilo do Elementor e CSS interno complexo.
   191→     */
   192→    private function scope_svg_styles( string $svg, string $scope_id ): string {
   193→        // Só aplica scoping em SVGs com classes genéricas .cls-N
   194→        if ( ! preg_match( '/\.cls-[\w-]+\s*\{/', $svg ) ) {
   195→            return $svg;
   196→        }
   197→
   198→        // Injetar data-scope no elemento <svg>
   199→        $svg = preg_replace( '/<svg\b/', '<svg data-scope="' . esc_attr( $scope_id ) . '"', $svg, 1 );
   200→
   201→        // Scopar apenas os seletores .cls-* dentro dos blocos <style>
   202→        $svg = preg_replace_callback(
   203→            '/(<style[^>]*>)(.*?)(<\/style>)/is',
   204→            static function ( $m ) use ( $scope_id ) {
   205→                $scoped = preg_replace_callback(
   206→                    '/(\.cls-[\w-]+(?:\s*,\s*\.cls-[\w-]+)*)\s*\{/',
   207→                    static function ( $r ) use ( $scope_id ) {
   208→                        $selectors = array_map( 'trim', explode( ',', $r[1] ) );
   209→                        $prefixed  = array_map(
   210→                            static fn( $s ) => '[data-scope="' . $scope_id . '"] ' . $s,
   211→                            $selectors
   212→                        );
   213→                        return implode( ', ', $prefixed ) . ' {';
   214→                    },
   215→                    $m[2]
   216→                );
   217→                return $m[1] . $scoped . $m[3];
   218→            },
   219→            $svg
   220→        );
   221→
   222→        return $svg;
   223→    }
   224→
   225→    protected function render() {
   226→        $s = $this->get_settings_for_display();
   227→
   228→        $name = ! empty( $s['svg_name'] ) ? $s['svg_name'] : '';
   229→
   230→        if ( empty( $name ) ) return;
   231→
   232→        $file = get_stylesheet_directory() . '/svg/' . $name . '.svg';
   233→
   234→        if ( ! file_exists( $file ) ) return;
   235→
   236→        $svg = file_get_contents( $file );
   237→        if ( empty( $svg ) ) return;
   238→
   239→        // Remover declaração XML (inválida em HTML5 inline)
   240→        $svg = preg_replace( '/<\?xml[^?]*\?>\s*/i', '', $svg );
   241→
   242→        // Isolar CSS interno com data-scope para evitar conflitos entre SVGs inlined
   243→        $svg = $this->scope_svg_styles( $svg, 'bsvg-' . $this->get_id() );
   244→
   245→        // Injetar class no <svg>
   246→        if ( ! empty( $s['svg_class'] ) ) {
   247→            $class = esc_attr( $s['svg_class'] );
   248→            if ( preg_match( '/\bclass="[^"]*"/', $svg ) ) {
   249→                $svg = preg_replace( '/\bclass="([^"]*)"/', 'class="$1 ' . $class . '"', $svg, 1 );
   250→            } else {
   251→                $svg = preg_replace( '/<svg\b/', '<svg class="' . $class . '"', $svg, 1 );
   252→            }
   253→        }
   254→
   255→        // Injetar id no <svg>
   256→        if ( ! empty( $s['svg_id'] ) ) {
   257→            $id = esc_attr( $s['svg_id'] );
   258→            if ( preg_match( '/\bid="[^"]*"/', $svg ) ) {
   259→                $svg = preg_replace( '/\bid="[^"]*"/', 'id="' . $id . '"', $svg, 1 );
   260→            } else {
   261→                $svg = preg_replace( '/<svg\b/', '<svg id="' . $id . '"', $svg, 1 );
   262→            }
   263→        }
   264→
   265→        // Envolver em <a> se link_enabled = 'yes'
   266→        if ( ! empty( $s['link_enabled'] ) && $s['link_enabled'] === 'yes' ) {
   267→            $href   = ! empty( $s['link_url'] )
   268→                ? esc_url( $s['link_url'] )
   269→                : esc_url( apply_filters( 'wpml_home_url', network_home_url( '/' ) ) );
   270→            $target = ( $s['link_target'] ?? '_self' ) === '_blank'
   271→                ? ' target="_blank" rel="noopener noreferrer"'
   272→                : '';
   273→            $svg    = '<a href="' . $href . '"' . $target . '>' . $svg . '</a>';
   274→        }
   275→
   276→        echo $svg; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
   277→    }
